import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is present value?", a: "Present value is what a future amount of money is worth today after discounting it for time and return expectations." },
  { q: "How do you calculate present value?", a: "Divide the future value by (1 + discount rate) raised to the number of periods." },
  { q: "What is the present value formula?", a: "For a lump sum, PV = FV / (1 + r)^n, where r is the discount rate and n is the number of periods." },
  { q: "What is discount rate?", a: "Discount rate is the return rate used to translate future cash flows into today's dollars." },
  { q: "What is the difference between present value and future value?", a: "Present value discounts future money back to today. Future value compounds today's money forward into the future." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const pvLump = (fv: number, rate: number, periods: number) => fv / Math.pow(1 + rate / 100, periods);
const pvAnnuity = (pmt: number, rate: number, periods: number) => rate === 0 ? pmt * periods : pmt * (1 - Math.pow(1 + rate / 100, -periods)) / (rate / 100);

export default function PresentValueCalculator() {
  useCurrencyVersion();
  const [futureValue, setFutureValue] = useState(100000);
  const [discountRate, setDiscountRate] = useState(7);
  const [periods, setPeriods] = useState(10);
  const [payment, setPayment] = useState(5000);
  const [mode, setMode] = useState<"lump" | "annuity">("lump");
  const result = useMemo(() => {
    const value = mode === "lump" ? pvLump(futureValue, discountRate, periods) : pvAnnuity(payment, discountRate, periods);
    const totalFuture = mode === "lump" ? futureValue : payment * periods;
    return { value, discount: totalFuture - value };
  }, [futureValue, discountRate, periods, payment, mode]);
  const rates = [3, 5, 7, 10, 15];
  const years = [5, 10, 20, 30];

  return (
    <>
      <SEOHead title="Free Present Value Calculator Online - Calculate PV of Any Future Amount Instantly | CalcHive" description="Free online present value calculator. Calculate the present value of any future cash flow or annuity at any discount rate and time period instantly. 100% free, no signup required." canonical="/present-value-calculator" keywords="free present value calculator, PV calculator free online, calculate present value free, discounted cash flow calculator free, NPV present value calculator free" category="Financial Calculators" breadcrumbName="Free Present Value Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Present Value Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate the present value of a future amount or recurring annuity payments.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "lump" | "annuity")} className={inputClass}><option value="lump">Future value lump sum</option><option value="annuity">Annuity payments</option></select></div>{mode === "lump" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Future value</label><input type="number" value={futureValue} onChange={(e) => setFutureValue(Number(e.target.value))} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Payment per period</label><input type="number" value={payment} onChange={(e) => setPayment(Number(e.target.value))} className={inputClass} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Discount rate (%)</label><input type="number" value={discountRate} onChange={(e) => setDiscountRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Number of periods</label><input type="number" value={periods} onChange={(e) => setPeriods(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Present Value</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.value)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center mt-4"><p className="text-xs text-muted-foreground">Discount amount</p><p className="text-lg font-extrabold text-foreground">{money(result.discount)}</p></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Present Value of Any Future Amount for Free</h2><p className="text-muted-foreground leading-relaxed">Present value discounts a future amount using PV = FV / (1 + r)^n. For annuities, each payment is discounted and added together.</p><h2 className="text-2xl font-bold text-foreground">How Discount Rate Affects Present Value</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Present Value of $100,000 at Different Rates and Years</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Discount Rate</th>{years.map((y) => <th key={y} className="text-left py-3 px-3">{y} Years PV</th>)}</tr></thead><tbody className="divide-y divide-border">{rates.map((r) => <tr key={r}><td className="py-2.5 px-3 font-semibold">{r}%</td>{years.map((y) => <td key={y} className="py-2.5 px-3">{money(pvLump(100000, r, y), 0)}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free PV and Discounted Cash Flow Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/present-value-calculator" headingLevel="h3" /></main>
    </>
  );
}


